import dlt
from pyspark.sql import functions as F
from pyspark.sql import Window

@dlt.table(name="step_1_textinput", comment="Sales Data")
def step_1_textinput():
    return spark.createDataFrame([['Widget A', 'East', '250.00', '2024-01-15', 'Active'], ['Widget B', 'West', '75.00', '2024-01-20', 'Active'], ['Widget A', 'East', '500.00', '2024-02-10', 'Active'], ['Widget C', 'Central', '150.00', '2024-02-15', 'Inactive'], ['Widget B', 'West', '300.00', '2024-03-01', 'Active'], ['Widget A', 'Central', '50.00', '2024-03-10', 'Active']], schema=['Product', 'Region', 'Amount', 'Date', 'Status'])

@dlt.table(name="step_2_formula", comment="Calculate Tax")
def step_2_formula():
    df = dlt.read("step_1_textinput")
    df = df.withColumn("TaxAmount", (F.col("Amount") * 0.13))
    return df

@dlt.table(name="step_3_filter", comment="High Value Only")
def step_3_filter():
    return dlt.read("step_2_formula").filter((F.col("Amount") > 100))

@dlt.table(name="step_4_select", comment="Rename Columns")
def step_4_select():
    df = dlt.read("step_3_filter")
    df = df.withColumnRenamed("Region", "SalesRegion")
    df = df.withColumnRenamed("Amount", "SalesAmount")
    df = df.withColumnRenamed("Date", "SaleDate")
    df = df.drop("Status")
    return df

@dlt.table(name="step_5_sort", comment="Sort by Region and Amount")
def step_5_sort():
    return dlt.read("step_4_select").orderBy(F.col("SalesRegion").asc(), F.col("SalesAmount").desc())

@dlt.table(name="step_6_summarize", comment="Summary by Region")
def step_6_summarize():
    return dlt.read("step_5_sort").groupBy("SalesRegion").agg(F.sum("SalesAmount").alias("TotalSales"), F.count("SalesAmount").alias("TransactionCount"))

@dlt.table(name="step_7_output", comment="Save Results")
def step_7_output():
    return dlt.read("step_6_summarize")  # Write target: 
